// CF05 WF_CTR_OPTIMIZE — normalize trigger, idempotency, fetch topic/project/competitor/scenes.
// Global fetch + $env per MEMORY.md (n8n 2.8.4 task runner compat).

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || raw;

const topicId = payload.topic_id;
const force = payload.force === true;

if (!topicId) {
  return [{
    json: {
      success: false,
      error: 'Provide { topic_id }',
      http_status: 400,
      via_webhook: viaWebhook
    }
  }];
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function sbGet(url, label) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) throw new Error(`${label} failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

// 1. Fetch topic
const topicUrl = `${supabaseUrl}/rest/v1/topics?id=eq.${topicId}&select=id,project_id,seo_title,original_title,narrative_hook,primary_keyword,title_variants_generated_at,script_review_status,topic_number`;
const topics = await sbGet(topicUrl, 'fetch topic');
const topic = Array.isArray(topics) && topics[0] ? topics[0] : null;

if (!topic) {
  return [{ json: { success: false, error: `Topic ${topicId} not found`, http_status: 404, via_webhook: viaWebhook } }];
}

// 2. Idempotency
if (!force && topic.title_variants_generated_at) {
  return [{
    json: {
      success: true,
      skipped: true,
      reason: 'Title variants already generated (pass force=true to regenerate)',
      topic_id: topicId,
      title_variants_generated_at: topic.title_variants_generated_at,
      http_status: 200,
      via_webhook: viaWebhook
    }
  }];
}

const projectId = topic.project_id;

// 3. Fetch project context
const projUrl = `${supabaseUrl}/rest/v1/projects?id=eq.${projectId}&select=niche,niche_description,niche_expertise_profile`;
const projArr = await sbGet(projUrl, 'fetch project');
const project = (projArr && projArr[0]) || {};

// 4. Fetch top-5 competitor outlier titles (may be empty if S2 hasn't run)
let competitorTitles = [];
try {
  const compUrl = `${supabaseUrl}/rest/v1/competitor_videos?project_id=eq.${projectId}&is_outlier=eq.true&select=title,views_7d&order=views_7d.desc.nullslast&limit=5`;
  const compRes = await fetch(compUrl, { method: 'GET', headers: sbHeaders });
  if (compRes.ok) {
    const arr = await compRes.json();
    competitorTitles = (arr || []).map(r => r.title).filter(Boolean);
  }
} catch (_) { /* non-fatal */ }

// 5. Fetch scenes for script text (narration_text) — script summary source
let scriptText = '';
try {
  const scenesUrl = `${supabaseUrl}/rest/v1/scenes?topic_id=eq.${topicId}&select=scene_number,narration_text&order=scene_number.asc&limit=400`;
  const scRes = await fetch(scenesUrl, { method: 'GET', headers: sbHeaders });
  if (scRes.ok) {
    const arr = await scRes.json();
    scriptText = (arr || []).map(s => s.narration_text || '').join(' ').trim();
  }
} catch (_) { /* non-fatal */ }

return [{
  json: {
    topic_id: topicId,
    project_id: projectId,
    topic,
    project,
    competitor_titles: competitorTitles,
    script_text: scriptText,
    has_script_text: scriptText.length > 200,
    via_webhook: viaWebhook,
    force,
    started_at: new Date().toISOString()
  }
}];

// Step A: Haiku 4.5 summarizer (cost-sensitive) -> 200-word script summary.
// Step B: Opus 4.6 generator -> 5 CTR-scored title variants via title_ctr_scorer.md template.
// Inline exponential backoff on both. Graceful fallback if either fails.

const data = $input.first().json;
if (data.success === false || data.skipped) return $input.item;

const anthropicKey = $env.ANTHROPIC_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

const topic = data.topic || {};
const project = data.project || {};
const topicTitle = topic.seo_title || topic.original_title || '';
const narrativeHook = topic.narrative_hook || '';
const primaryKeyword = topic.primary_keyword || topicTitle.split(' ').slice(0, 3).join(' ');
const niche = project.niche || '';
const nicheContext = project.niche_description || niche || 'general audience';
const targetAudience = project.niche_expertise_profile || 'YouTube viewers interested in this topic';
const competitorTitles = data.competitor_titles || [];
const scriptText = data.script_text || '';

async function callClaude(model, maxTokens, userPrompt, label, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model,
          max_tokens: maxTokens,
          messages: [{ role: 'user', content: userPrompt }]
        })
      });
      if (res.ok) {
        const body = await res.json();
        return { ok: true, text: body.content?.[0]?.text || '', attempts: attempt };
      }
      const errBody = await res.text();
      if (res.status === 429) await sleep(30000);
      lastErr = new Error(`HTTP ${res.status}: ${errBody.slice(0, 300)}`);
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

function parseJson(text) {
  if (!text) return null;
  const clean = text.replace(/```json|```/g, '').trim();
  try { return JSON.parse(clean); } catch {}
  const m = clean.match(/\{[\s\S]*\}/);
  if (m) { try { return JSON.parse(m[0]); } catch {} }
  return null;
}

// Step A: Summarize script (Haiku) or fallback
let scriptSummary;
let summaryCostUsd = 0;
const summaryStart = Date.now();

if (scriptText.length > 200) {
  // Cap script at ~50k chars to stay under Haiku input window comfortably
  const cappedScript = scriptText.slice(0, 50000);
  const summaryPrompt = `Summarize this YouTube video script in exactly 200 words, focusing on the core argument, the main claims revealed, and the specific numbers/facts/stories that anchor the narrative. No preamble — just the summary.\n\nSCRIPT:\n${cappedScript}`;
  const haikuRes = await callClaude('claude-haiku-4-5-20251001', 500, summaryPrompt, 'haiku_summary', 4);
  if (haikuRes.ok && haikuRes.text.length > 50) {
    scriptSummary = haikuRes.text.trim();
    summaryCostUsd = 0.005;
  } else {
    scriptSummary = `${topicTitle}. ${narrativeHook}`.trim().slice(0, 800);
  }
} else {
  scriptSummary = `${topicTitle}. ${narrativeHook}`.trim().slice(0, 800) || 'No script summary available';
}

// Step B: Build title_ctr_scorer user prompt
const competitorBlock = competitorTitles.length
  ? competitorTitles.map(t => `  - "${t}"`).join('\n')
  : '  (no competitor outlier titles available — generate from formulas alone)';

const userPrompt = `TITLE GENERATION + SCORING REQUEST

Video Topic: ${topicTitle}
Niche: ${nicheContext}
Target Audience: ${targetAudience}
Script Summary (200 words): ${scriptSummary}
Primary Keyword: ${primaryKeyword}
Competitor Top Titles (for pattern reference):
${competitorBlock}

GENERATE 5 TITLE VARIANTS using these formulas:

FORMULA A — NUMBERS + CONSEQUENCE:
Structure: [Specific Number] [Topic Nouns] That [Consequence for Audience]

FORMULA B — HIDDEN TRUTH:
Structure: Why [Common Belief/Behavior] Is [Surprising Negative Consequence]

FORMULA C — INSIDER REVEAL:
Structure: The [Topic] [Strategy/Secret/Trick] [Authority Group] [Does/Doesn't Want You to Know]

FORMULA D — IDENTITY CHALLENGE:
Structure: [What You Think Is True] vs [What's Actually True] (or "Stop [Doing X]" format)

FORMULA E — STORY HOOK:
Structure: I [Did Surprising Thing Related to Topic] — Here's What Happened After [Timeframe/Scale]

For each of the 5 titles, score against these factors (be strict):
- Length (55-70 chars) — max 20 (55-65 = 20pts, 65-70 = 15pts, 50-55 = 10pts, other = 0)
- Number present — max 15 (contains specific number = 15pts)
- Power word (secret/never/stop/actually/hidden/real/truth/worst/best) — max 10
- Curiosity gap — max 15 (clear info gap only the video can close = 15, partial = 7)
- Emotional trigger — max 10 (Fear=10, Desire=8, Curiosity=6, Neutral=0)
- Keyword in first 40 chars — max 10
- No clickbait penalty (deliverability) — max 20

RULES:
- Never use ALL CAPS for entire words (1-2 words max).
- Never end in "...".
- Titles must match actual script content.
- Primary keyword appears naturally.
- Prefer concrete numbers over vague claims.

Return ONLY valid JSON:
{
  "title_options": [
    {
      "title": "<string>",
      "ctr_score": <int 0-100>,
      "formula_pattern": "<A|B|C|D|E>",
      "char_count": <int>,
      "scoring_breakdown": {
        "length": <int>, "number": <int>, "power_word": <int>, "curiosity_gap": <int>,
        "emotional_trigger": <int>, "keyword_position": <int>, "deliverability": <int>
      },
      "reasoning": "<1 sentence>"
    }
  ],
  "recommended_index": <0-4>,
  "recommended_reasoning": "<1 sentence>"
}`;

const opusStart = Date.now();
const opusRes = await callClaude('claude-opus-4-6', 2500, userPrompt, 'opus_5_variants', 4);

let parsed = opusRes.ok ? parseJson(opusRes.text) : null;

// Normalize — pad to 5, clamp scores, coerce fields
function fallbackVariant(title) {
  return {
    title: String(title || topicTitle).slice(0, 500),
    ctr_score: 50,
    formula_pattern: 'fallback',
    char_count: String(title || topicTitle).length,
    scoring_breakdown: { length: 0, number: 0, power_word: 0, curiosity_gap: 0, emotional_trigger: 0, keyword_position: 0, deliverability: 0 },
    reasoning: 'Fallback — CTR generation failed or produced fewer than 5 variants'
  };
}

let titleOptions = Array.isArray(parsed?.title_options) ? parsed.title_options : [];
titleOptions = titleOptions.slice(0, 5).map(v => ({
  title: String(v.title || topicTitle).slice(0, 500),
  ctr_score: Math.max(0, Math.min(100, Math.round(Number(v.ctr_score) || 0))),
  formula_pattern: ['A', 'B', 'C', 'D', 'E', 'fallback'].includes(v.formula_pattern) ? v.formula_pattern : 'A',
  char_count: Number.isFinite(v.char_count) ? v.char_count : String(v.title || '').length,
  scoring_breakdown: v.scoring_breakdown || {},
  reasoning: String(v.reasoning || '').slice(0, 500)
}));

while (titleOptions.length < 5) titleOptions.push(fallbackVariant(topicTitle));

let recommendedIndex = Number.isInteger(parsed?.recommended_index) ? parsed.recommended_index : 0;
if (recommendedIndex < 0 || recommendedIndex > 4) recommendedIndex = 0;
const recommendedReasoning = String(parsed?.recommended_reasoning || titleOptions[recommendedIndex]?.reasoning || 'Highest CTR score among variants').slice(0, 1000);

const opusOk = !!parsed;
const opusCostUsd = opusOk ? 0.035 : 0;
const totalCostUsd = Math.round((summaryCostUsd + opusCostUsd) * 1000) / 1000;

return [{
  json: {
    ...data,
    script_summary: scriptSummary,
    summary_duration_ms: Date.now() - summaryStart,
    summary_cost_usd: summaryCostUsd,
    title_options: titleOptions,
    title_recommended_index: recommendedIndex,
    title_ctr_reasoning: recommendedReasoning,
    opus_ok: opusOk,
    opus_error: opusOk ? null : (opusRes.error || 'parse_failed'),
    opus_duration_ms: Date.now() - opusStart,
    opus_cost_usd: opusCostUsd,
    total_cost_usd: totalCostUsd
  }
}];

// PATCH topics with variants + recommended index. Log to production_logs.
const data = $input.first().json;

if (data.success === false) {
  return [{ json: data }];
}
if (data.skipped) {
  return [{ json: data }];
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const topicId = data.topic_id;
const projectId = data.project_id;
const titleOptions = data.title_options || [];
const recIdx = data.title_recommended_index || 0;
const recommended = titleOptions[recIdx] || titleOptions[0] || null;
const nowIso = new Date().toISOString();

const patch = {
  title_options: titleOptions,
  title_ctr_score: recommended?.ctr_score ?? null,
  title_recommended_index: recIdx,
  title_ctr_reasoning: data.title_ctr_reasoning,
  selected_title: recommended?.title || null,
  title_variants_generated_at: nowIso
};

let patchError = null;
try {
  const res = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${topicId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(patch)
  });
  if (!res.ok) patchError = `PATCH failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`;
} catch (e) {
  patchError = e.message;
}

// production_logs — record the Opus variant generation
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: 'ctr_optimize',
      scene_number: null,
      action: 'opus_5_variants',
      status: patchError ? 'partial' : (data.opus_ok ? 'success' : 'fallback'),
      duration_ms: (data.opus_duration_ms || 0) + (data.summary_duration_ms || 0),
      cost_usd: data.total_cost_usd || 0,
      retry_count: 0
    })
  });
} catch (_) { }

return [{
  json: {
    success: !patchError,
    topic_id: topicId,
    project_id: projectId,
    title_options: titleOptions,
    title_ctr_score: patch.title_ctr_score,
    title_recommended_index: recIdx,
    title_ctr_reasoning: patch.title_ctr_reasoning,
    selected_title: patch.selected_title,
    title_variants_generated_at: nowIso,
    opus_ok: data.opus_ok,
    total_cost_usd: data.total_cost_usd,
    patch_error: patchError,
    http_status: patchError ? 500 : 200,
    via_webhook: data.via_webhook
  }
}];
